values
  ('a1100000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000001', 'Organizacao, Carga e Exigencias do Trabalho', 0),
  ('a1100000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000001', 'Jornada, Ritmo e Conciliacao Trabalho-Vida', 1),
  ('a1100000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000001', 'Lideranca, Gestao, Justica e Clareza de Papeis', 2),
  ('a1100000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000001', 'Relacoes Interpessoais, Respeito e Apoio Social', 3),
  ('a1100000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000001', 'Desenvolvimento, Reconhecimento e Seguranca de Carreira', 4),
  ('a1100000-0000-0000-0000-000000000006', 'a1000000-0000-0000-0000-000000000001', 'Condicoes e Contexto Material de Trabalho', 5),
  ('a1100000-0000-0000-0000-000000000007', 'a1000000-0000-0000-0000-000000000001', 'Saude Mental, Bem-Estar e Engajamento', 6);
insert into public.questionnaire_questions (id, section_id, prompt, answer_type, scoring_direction, weight, is_required, is_active, order_index, hazard_code, source_reference, severity_score, severity_label, circumstances_text, outcomes_text, recommended_actions_text, monitoring_guidance_text)
values
  ('c1000000-0000-0000-0000-000000000001', 'a1100000-0000-0000-0000-000000000001', 'Acúmulo de atividades ou de funções', 'likert_1_5', 'negative', 3.0, true, true, 0, 1, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Organização inadequada do trabalho (ex: má distribuição de tarefas, falta de planejamento, cargos mal definidos). 2 - Falta de recursos humanos (ex: º insuficiente de funcionários, falta de treinamento ou de ferramentas adequadas). 3 - Pressão por resultado (ex: metas inatingíveis, prazos apertados etc). 4 - Liderança inadequada, com comunicação deficiente e/falta de apoio.', 'Síndrome de Burnout Estresse, ansiedade, episódio depressivo, irritabilidade, tensão e isolamento', '1 - Reanálise de cargos, funções e responsabilidades. 2 - Análise e monitoramento da carga de trabalho. 3 - Automatizar os processos repetitivos e burocráticos. 4 - Fiscalização e suporte da CIPA. 5 - Fornecer ferramentas de organização pessoal do trabalho (planners, agenda etc). 6 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 7 - Definir claramente as funções e responsabilidades de cada cargo, evitando a sobreposição de tarefas. 8 - Implementar sistema de planejamento de projetos e atividades, definindo prazos realistas e alocando os recursos necessários. 9 - Evitar a imposição de ritmos de trabalho excessivamente intensos ou inflexíveis.', '1 - Análise da descrição de cargos e funções. 2 - Monitoramento da carga de trabalho. 3 - Pesquisas de percepção da carga de trabalho. 4 - Análise de indicadores de saúde. 5 - Entrevistas individuais com trabalhadores.'),
  ('c1000000-0000-0000-0000-000000000002', 'a1100000-0000-0000-0000-000000000004', 'Ameaças ou violência de terceiros', 'likert_1_5', 'negative', 4.0, true, true, 0, 2, 'Safe2Mind', 4, 'Alta Incapacidade de realizar as tarefas do trabalho', '1 - Natureza do trabalho (ex: segurança, atendimento ao público em áreas de risco). 2 - Falta de medidas de segurança adequadas (ex: câmeras, alarmes, seguranças). 3 - Falta de treinamento para lidar com situações de violência. 4 - Ambiente de trabalho inseguro ou mal iluminado. 5 - Falta de apoio psicológico para vítimas de violência.', 'Transtorno de estress pós-traumático, Estresse, distúrbios do sono e isolamento social', '1 - Criar protocolos claros para lidar com ameaças e violência, conforme NR-1, Item 1.5.6. 2 - Priorizar a segurança e o bem-estar dos trabalhadores, conforme Art. 5º, inciso VI da Lei nº 6.514/77. 3 - Implementação de políticas de segurança e sanção para agressores. 4 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 5 - Implementar vigilância, controle de acesso e treinamento em segurança, coforme Art. 5º, inciso VI da Lei nº 6.514/77. 6 - Treinamento e capacitação para situações de conflitos e confrontos. 7 - Fiscalização e suporte da CIPA. 8 - Disponibilizar acompanhamento e apoio jurídico. 9 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 10 - Implementar vigilância, controle de acesso e treinamento em segurança, coforme Art. 5º, inciso VI da Lei nº 6.514/77. 11 - Criar protocolos claros para lidar com ameaças e violência, conforme NR-1, Item 1.5.6.', '1 - Registro e investigação de todos os incidentes de ameaça ou violência. 2 - Monitoramento das áreas de maior risco. 3 - Entrevistas com trabalhadores para identificar percepções de insegurança. 4 - Análise de registros de ocorrências policiais.'),
  ('c1000000-0000-0000-0000-000000000003', 'a1100000-0000-0000-0000-000000000003', 'Aplicação inconsistente das regras', 'likert_1_5', 'negative', 3.0, true, true, 0, 3, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Falta de políticas claras e bem definidas. 2 - Falta de treinamento dos gestores sobre as políticas da empresa. 3 - Falta de critérios objetivos para a tomada de decisões. 4 - Favoritismo ou discriminação. 5 - Comunicação ineficaz sobre as regras e procedimentos.', 'Transtorno de ansiedade generalizada Ansiedade, desmotivação, distúrbios do sono e conflitos interpessoais', '1 - Revisão e garantia de padronização das normas e regras da empresa. 2 - Implementação de código de conduta interno. 3 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 4 - Divulgação e treinamento das políticas internas. 5 - Fiscalização e suporte da CIPA. 6 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 7 - Definir e comunicar políticas e procedimentos transparentes. 8 - Capacitar gestores para aplicar as regras de forma justa e consistente. 9 - A NR-1 no Item 1.4.1, estabelece a responsabilidade do empregador em capacitar os trabalhadores, incluindo os gestores, para a segurança e saúde no trabalho. 10 - Criar canais para denúncias e resolução de conflitos.', '1 - Revisão e padronização das políticas e procedimentos da empresa. 2 - Treinamento dos gestores sobre a aplicação consistente das regras. 3 - Canais de denúncia para relatar casos de inconsistência. 4 - Auditoria interna para verificar a aplicação das regras.'),
  ('c1000000-0000-0000-0000-000000000004', 'a1100000-0000-0000-0000-000000000004', 'Assédio de qualquer natureza', 'likert_1_5', 'negative', 3.0, true, true, 1, 4, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Cultura organizacional que tolera ou normaliza comportamentos abusivos. 2 - Falta de políticas claras e eficazes de prevenção e combate ao assédio. 3 - Liderança permissiva ou conivente com o assédio. 4 - Falta de treinamento e conscientização sobre o tema. 5 - Desequilíbrio de poder entre os trabalhadores. 6 - Dificuldade em denunciar o assédio por medo de represálias.', 'Transtorno de estress pós-traumático Ansiedade, depressão, estresse, baixa autoestima, ideaçao suicida e isolamento social', '1 - Implementar política de tolerância zero com canais de denúncia confidenciais, conforme NR- 5 e a Lei 14.540, de 2023. 2 - Implementar o código de conduta e sansões disciplinares. 3 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 4 - Oferecer treinamento sobre ética, respeito e combate ao assédio, conforme NR-1,item 1.4.1. 5 - Fiscalização e suporte da CIPA. 6 - Monitorar o clima organizacional. 7 - Estimular a denúncia em situações de assédio de qualquer natureza. 8 - Disponibilizar apoio jurídico. 9 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 10 - Implementar política de tolerância zero com canais de denúncia confidenciais, conforme NR-5 e a Lei 14.540, de 2023. 11 - Oferecer treinamento sobre ética, respeito e combate ao assédio, conforme NR-1,item 1.4.1. 12 - Promover uma cultura organizacional que valorize o respeito e a diversidade.', '1 - Implementação de política de tolerância zero ao assédio. 2 - Treinamento sobre assédio para todos os trabalhadores. 3 - Canais de denúncia confidenciais e eficientes. 4 - Investigação rigorosa de todas as denúncias.'),
  ('c1000000-0000-0000-0000-000000000005', 'a1100000-0000-0000-0000-000000000002', 'Ausência de pausas e locais definidos para descanso durante a jornada', 'likert_1_5', 'negative', 3.0, true, true, 0, 5, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Cultura organizacional que não valoriza o descanso. 2 - Falta de planejamento do trabalho. 3 - Sobrecarga de trabalho. 4 - Dificuldade em interromper as tarefas.', 'Síndrome de Burnout Estresse, ansiedade, irritabilidade, tensão e isolamento', '1 - Garantir pausas adequadas durante o expediente, conforme NR-17.5.5 e Art. 71 da CLT. 2 - Desenvolver e comunicar política de intervalos e descansos. 3 - Monitorar o cumprimento das pausas. 4 - Oferecer flexibilidade de horário, sempre que possível. 5 - Implementar cultura de valorização do bem-estar. 6 - Criar pausas e locais de descanso adequados (NR-17). 7 - Oferecer EPI''s que diminuem a fadiga e o estresse, quando aplicável. 8 - Implementar pausas obrigatórias e remuneradas, conforme NR-17 e Art. 71 da CLT. 9 - Permitir que os trabalhadores façam pausas quando necessário. 10 - Informar os trabalhadores sobre os benefícios das pausas para a saúde e o desempenho.', '1 - Monitoramento do cumprimento das pausas (folhas de ponto, sistemas de controle de acesso). 2 - Disponibilização de locais de descanso adequados. 3 - Pesquisas com trabalhadores sobre a qualidade das pausas e dos locais de descanso.'),
  ('c1000000-0000-0000-0000-000000000006', 'a1100000-0000-0000-0000-000000000001', 'Cadência do trabalho imposta por um equipamento', 'likert_1_5', 'negative', 3.0, true, true, 1, 6, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Design inadequado do processo de trabalho. 2 - Falta de flexibilidade para ajustar o ritmo às necessidades dos trabalhadores. 3 - Pressão excessiva por produtividade. 4 - Falta de pausas adequadas. 5 - Falta de treinamento para lidar com o ritmo da máquina.', 'Síndrome de Burnout Estresse, ansiedade, irritabilidade, tensão e isolamento', '1 - Reavaliar o design do processo de trabalho, conforme AET (Análise Ergonômica do Trabalho). 2 - Capacitar os trabalhadores para lidar com o ritmo da máquina, conforme NR-1 e NR-17. 3 - Flexibilizar a cadência imposta pelo equipamento, sempre que possível. 4 - Oferecer EPI''s que ajudem a reduzir o impacto da cadência do equipamento, quando aplicável. 5 - Ajustar o ritmo da máquina às necessidades dos trabalhadores, conforme NR-17, item 17.6. 6 - Implementar pausas regulares e adequadas, conforme o mesmo item. 7 - Capacitar os trabalhadores para lidar com o ritmo da máquina, conforme NR-1.', '1 - Análise ergonômica do trabalho (AET) para avaliar o impacto da cadência na saúde dos trabalhadores. 2 - Monitoramento da produção e da qualidade do trabalho. 3 - Pesquisas com trabalhadores sobre a percepção do ritmo de trabalho.'),
  ('c1000000-0000-0000-0000-000000000007', 'a1100000-0000-0000-0000-000000000001', 'Carga de trabalho excessiva', 'likert_1_5', 'negative', 3.0, true, true, 2, 7, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Metas irrealistas. 2 - Falta de pessoal. 3 - Falta de planejamento e organização do trabalho. 4 - Pressão por produtividade. 5 - Falta de automatização de tarefas. 6 - Cultura organizacional que valoriza o excesso de trabalho.', 'Síndrome de Burnout Estresse, ansiedade, irritabilidade, tensão e isolamento', '1 - Análise e monitoramento da carga de trabalho. 2 - Redesenho do trabalho e distribuição de tarefas. 3 - Oferecer programa de bem-estar coletivo. 4 - Automatizar tarefas repetitivas e de baixo valor agregado. 5 - Fiscalização e suporte da CIPA. 6 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 7 - Otimizar processos e distribuir tarefas de forma equitativa, conforme NR-17. 8 - Reavaliar e aumentar o número de funcionários para atender à demanda. 9 - Definir prioridades claras e realistas.', '1 - Análise da carga de trabalho (número de tarefas, prazos, complexidade). 2 - Monitoramento das horas extras. 3 - Pesquisas com trabalhadores sobre a percepção da carga de trabalho.'),
  ('c1000000-0000-0000-0000-000000000008', 'a1100000-0000-0000-0000-000000000003', 'Comunicação deficente', 'likert_1_5', 'negative', 2.0, true, true, 1, 8, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de canais de comunicação abertos e transparentes. 2 - Falta de feedback regular e construtivo. 3 - Linguagem inadequada ou ambígua. 4 - Sobrecarga de informações. 5 - Falta de clareza nas instruções e expectativas. 6 - Barreiras hierárquicas que dificultam a comunicação.', 'Episódios depressivos Ansiedade, frustração, tensão emocional, conflitos de relacionamento', '1 - Realizar um mapeamento, análise e melhoria dos canais de comunicação existentes. 2 - Definir protocolos de comunicação claros e objetivos. 3 - Oferecer treinamento em comunicação para todos os trabalhadores. 4 - Promover a cultura de comunicação transparente e segurança psicológica. 5 - Realizar reuniões regulares com os trabalhadores para discutir assuntos relevantes para o trabalho. 6 - Oferecer treinamento aos trabalhadores que apresentem dificuldades de comunicação. 7 - Implementar canais de comunicação transparentes e acessíveis. 8 - Estabelecer rotinas de feedback construtivo. 9 - Oferecer treinamento em habilidades de comunicação.', '1 - Análise dos canais de comunicação da empresa. 2 - Pesquisas com trabalhadores sobre a qualidade da comunicação. 3 - Monitoramento do fluxo de informações.'),
  ('c1000000-0000-0000-0000-000000000009', 'a1100000-0000-0000-0000-000000000002', 'Desequilíbrio entre tempo de trabalho e tempo de repouso', 'likert_1_5', 'negative', 3.0, true, true, 1, 9, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Cultura organizacional que valoriza o excesso de trabalho. 2 - Falta de políticas de limitação da jornada de trabalho. 3 - Sobrecarga de trabalho. 4 - Horários inflexíveis. 5 - Dificuldade em conciliar trabalho e vida pessoal. 6 - Falta de pausas adequadas durante o expediente.', 'Síndrome de Burnout Disturbios do sono, irritabilidade, tensão emocional, redução da interação social', '1 - Realizar o planejamento adequado da jornada de trabalho, conforme CLT. 2 - Oferecer flexibilidade de horário, sempre que possível. 3 - Promover a cultura WLB (Work life balance) para equilibrar vida pessoal-profissional. 4 - Realizar campanhas de comunicação e conscientização sobre a importância do equilíbrio pessoal-profissional. 5 - Fiscalização e suporte da CIPA. 6 - Oferecer espaços de descompressão mental e emocional. 7 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 8 - Implementar políticas de limitação da jornada e horas extras, conforme Art. 58 e Art. 59 da CLT. 9 - Garantir pausas adequadas durante o expediente, conforme NR-17.5.5 e Art. 71 da CLT. 10 - Oferecer horários flexíveis e opções de trabalho remoto, se a função permitir.', '1 - Monitoramento das horas de trabalho e descanso. 2 - Pesquisas com trabalhadores sobre o equilíbrio entre trabalho e vida pessoal. 3 - Análise das políticas de folgas e férias.'),
  ('c1000000-0000-0000-0000-000000000010', 'a1100000-0000-0000-0000-000000000004', 'Discriminação de qualquer natureza', 'likert_1_5', 'negative', 3.0, true, true, 2, 10, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Cultura organizacional que tolerante à discriminação. 2 - Práticas e atividades excludentes da gestão. 3 - Falta de políticas claras e eficazes contra discriminação. 4 - Liderança permissiva ou conivente. 5 - Falta de treinamento e conscientização sobre o tema. 6 - Desequilíbrio de poder entre os trabalhadores.', 'Transtorno de estress pós-traumático Ansiedade, depressão, estresse, baixa autoestima, ideaçao suicida e isolamento social', '1 - Implementar política de não-discriminação e igualdade. 2 - Implementar código de conduta ético e inclusivo. 3 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 4 - Aplicar sanções adequadas aos autores de comportamentos discriminatórios, de acordo com a gravidade da ofensa, conforme Art. 482 da CLT e Lei 7.716/89. 5 - Realizar treinamento e conscientização sobre respeito, inclusão e diversidade. 6 - Utilizar comunicação visual inclusiva em todos os materiais da empresa. 7 - Promover o dia da diversidade e inclusão, estimulando a interação entre os diferentes grupos de trabalhadores (21/5). 8 - Fiscalização e suporte da CIPA. 9 - Oferecer programa de acolhimento a trabalhadores das minorias. 10 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 11 - Implementar política antidiscriminação clara e abrangente, que proíba qualquer forma de discriminação. 12 - Criar canais de denúncia confidenciais, onde as vítimas de discriminação possam relatar os casos sem medo de represálias. 13 - Aplicar sanções adequadas aos autores de comportamentos discriminatórios, de acordo com a gravidade da ofensa, conforme Art. 482 da CLT e Lei 7.716/89.', '1 - Implementação de política de não discriminação e igualdade. 2 - Treinamento sobre diversidade e inclusão. 3 - Canais de denúncia confidenciais e eficientes. 4 - Monitoramento da diversidade na empresa.'),
  ('c1000000-0000-0000-0000-000000000011', 'a1100000-0000-0000-0000-000000000003', 'Excesso de conflitos hierárquicos no trabalho', 'likert_1_5', 'negative', 3.0, true, true, 2, 11, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Liderança autocrática ou inconsistente. 2 - Falta de clareza nas funções e responsabilidades. 3 - Comunicação ineficaz. 4 - Falta de treinamento em habilidades de resolução de conflitos. 5 - Cultura organizacional que não valoriza o diálogo e a colaboração. 6 - Competição excessiva entre os trabalhadores.', 'Transtornos de Adaptação Estresse, ansiedade, depressão, insegurança, tensão emocional, conflitos, fadiga mental', '1 - Definir e comunicar autoridades e limites de cada função na hierarquia da empresa. 2 - Manter organograma claro e acessível. 3 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 4 - Treinamento de gestão de conflitos e inteligência emocional. 5 - Promover cultura de segurança psicológica. 6 - Fiscalização e suporte da CIPA. 7 - Oferecer mediação de conflitos. 8 - Oferecer capacitação individual para os líderes. 9 - Oferecer espaços de descompressão mental e emocional. 10 - Treinar líderes em habilidades de comunicação e resolução de conflitos. 12 - Definir claramente as funções e responsabilidades de cada um. 13 - Promover uma cultura de diálogo e colaboração.', '1 - Análise da estrutura organizacional. 2 - Treinamento em gestão de conflitos para líderes. 3 - Canais de mediação de conflitos. 4 - Pesquisas com trabalhadores sobre o clima organizacional.'),
  ('c1000000-0000-0000-0000-000000000012', 'a1100000-0000-0000-0000-000000000007', 'Excesso de demandas emocionais no trabalho', 'likert_1_5', 'negative', 2.0, true, true, 0, 12, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Natureza do trabalho (ex: atendimento ao público, profissionais de saúde). 2 - Falta de treinamento em habilidades de comunicação e gerenciamento de emoções. 3 - Falta de suporte emocional e psicológico. 4 - Exposição a situações de sofrimento ou violência. 5 - Falta de reconhecimento pelo trabalho emocional realizado.', 'Disturbios do sono, irritabilidade, tensão emocional, redução da interação social', '1 - Controlar indicadores de bem-estar emocional, como taxa de absenteísmo, o número de queixas e reclamações e os resultados de pesquisas de clima organizacional. 2 - Capacitação em inteligência emocional. 3 - Promover cultura organizacional de respeito e empatia. 4 - Oferecer espaços de descompressão mental e emocional. 5 - Oferecer supervisão de apoio para os trabalhadores que lidam com altas demandas emocionais. 6 - Oferecer treinamento em habilidades de comunicação e gerenciamento de emoções. 7 - Disponibilizar apoio psicológico e emocional o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde) inclui a assistência psicológica como uma das ações de saúde do trabalhador]. 8 - Valorizar o trabalho emocional realizado pelos trabalhadores.', '1 - Identificação das funções com maior demanda emocional. 2 - Treinamento em inteligência emocional para os trabalhadores. 3 - Supervisão de apoio para os trabalhadores que lidam com altas demandas emocionais. 4 - Disponibilização de apoio psicológico.'),
  ('c1000000-0000-0000-0000-000000000013', 'a1100000-0000-0000-0000-000000000001', 'Excesso de situações de estresse', 'likert_1_5', 'negative', 3.0, true, true, 3, 13, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Carga de trabalho excessiva. 2 - Prazos apertados. 3 - Falta de recursos. 4 - Falta de controle sobre o trabalho. 5 - Comunicação ineficaz. 6 - Clima organizacional negativo. 7 - Insegurança no emprego.', 'Transtorno de Ansiedade Generalizada Síndrome de Burnout Estresse, ansiedade, depressão, dificuldade de concentração, distúrbios da memória, irritabilidade, isolamento social', '1 - Implementar programas de bem-estar no trabalho. 2 - Implementar canais para que os trabalhadores possam expressar suas preocupações sobre as situações de estresse no trabalho. 3 - Criar espaço para descompressão mental e relaxamento. 4 - Oferecer treinamento de gestão do estresse. 5 - Fiscalização e suporte da CIPA. 6 - Oferecer EPI''s que diminuem a fadiga e o estresse, quando aplicável. 7 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 8 - Oferecer treinamento em gerenciamento do tempo e técnicas de relaxamento. 9 - Melhorar a comunicação e o clima organizacional. 10 - Disponibilizar apoio psicológico e programas de bem-estar.', '1 - Identificação das fontes de estresse no trabalho. 2 - Implementação de programas de gestão do estresse. 3 - Disponibilização de apoio psicológico. 4 - Monitoramento dos indicadores de saúde (absenteísmo, licenças médicas).'),
  ('c1000000-0000-0000-0000-000000000014', 'a1100000-0000-0000-0000-000000000001', 'Exigência de alto nível de concentração, atenção ou memória', 'likert_1_5', 'negative', 2.0, true, true, 4, 14, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Natureza do trabalho. 2 - Falta de pausas adequadas. 3 - Ruído e outras distrações no ambiente de trabalho. 4 - Falta de treinamento para desenvolver habilidades de concentração.', 'Estresse, ansiedade, irritabilidade, tensão e isolamento', '1 - Redesenhar o trabalho para reduzir ou eliminar as exigências cognitivas excessivas, sempre que possível. 2 - Simplificar as tarefas complexas, dividindo-as em etapas menores e mais fáceis de serem executadas. 3 - Monitorar a fadiga mental, utilizando indicadores como o número de erros cometidos. 4 - Promover um ambiente de trabalho livre de distrações e interrupções. 5 - Oferecer espaços de descompressão mental e emocional. 6 - Implementar pausas regulares para descanso mental, conforme NR-17. 7 - Reduzir o ruído e outras distrações no ambiente de trabalho, conforme NR-15. 8 - Oferecer treinamento em técnicas de concentração e memorização.', '1 - Análise das tarefas que exigem alto nível de concentração, atenção ou memória. 2 - Implementação de medidas para reduzir a carga cognitiva (ex: pausas, rodízio de tarefas). 3 - Monitoramento da fadiga mental.'),
  ('c1000000-0000-0000-0000-000000000015', 'a1100000-0000-0000-0000-000000000001', 'Exigências contraditórias', 'likert_1_5', 'negative', 3.0, true, true, 5, 15, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Falta de comunicação entre as diferentes áreas da empresa. 2 - Metas conflitantes. 3 - Expectativas contraditórias. 4 - Falta de clareza sobre as prioridades.', 'Transtorno de Ansiedade Generalizada Estresse, ansiedade, depressão, dificuldade de concentração, distúrbios da memória, irritabilidade, isolamento social', '1 - Eliminar as ambiguidades e garantir a consistência e coerência dos processos e funções. 2 - Definir claramente os papéis e responsabilidades de cada função. 3 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 4 - Utilizar ferramentas de gestão de projetos que facilitem a comunicação e a colaboração entre os membros da equipe. 5 - Fiscalização e suporte da CIPA. 6 - Oferecer apoio para os trabalhadores que lidam com exigências contraditórias, com orientações para lidar com a situação. 7 - Melhorar a comunicação entre as diferentes áreas da empresa. 8 - Definir prioridades claras e realistas. 9 - Garantir que as metas e expectativas estejam alinhadas.', '1 - Análise das funções e tarefas para identificar exigências contraditórias. 2 - Comunicação clara das prioridades. 3 - Treinamento em gestão de conflitos. 4 - Apoio para os trabalhadores que lidam com exigências contraditórias.'),
  ('c1000000-0000-0000-0000-000000000016', 'a1100000-0000-0000-0000-000000000003', 'Falta de autonomia no trabalho', 'likert_1_5', 'negative', 2.0, true, true, 3, 16, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Liderança autocrática. 2 - Falta de confiança na capacidade dos trabalhadores. 3 - Processos de trabalho rígidos e inflexíveis. 4 - Falta de oportunidades de tomar decisões.', 'Episódios depressivos Redução da autoestima, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Fazer reuniões setoriais de gestão compartilhada para discutir problemaXsolução cotidianos. 2 - Definir limites da autonomia na descrição de cargos. 3 - Delegar autonomia aos trabalhadores, permitindo que resolvam problemas de forma independente, dentro das suas atribuições. 4 - Treinar a liderança sobre delegação de tarefas. 5 - Oferecer desenvolvimento individual aos colaboradores que desejam incorporar mais responsabilidade e autonomia na sua função. 6 - Delegar responsabilidades e dar aos trabalhadores mais controle sobre seu trabalho. 7 - Valorizar a iniciativa e a criatividade dos trabalhadores. 8 - Oferecer flexibilidade nas tarefas e métodos de trabalho.', '1 - Análise das funções e tarefas para identificar oportunidades de aumentar a autonomia. 2 - Delegação de responsabilidades. 3 - Treinamento em tomada de decisão.'),
  ('c1000000-0000-0000-0000-000000000017', 'a1100000-0000-0000-0000-000000000003', 'Falta de clareza na definição das funções', 'likert_1_5', 'negative', 2.0, true, true, 4, 17, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Descrição de cargos imprecisa ou desatualizada. 2 - Falta de comunicação sobre as responsabilidades de cada um. 3 - Mudanças frequentes nas funções sem comunicação adequada.', 'Estresse, ansiedade, depressão, dificuldade de concentração, irritabilidade, isolamento social', '1 - Garantir a clareza na descrição de cargos. 2 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 3 - Criar manuais e procedimentos padrão para atividades e funções. 4 - Manter a descrição de cargos acessíveis a todos os colaboradores. 5 - Treinar, periodicamente, os colaboradores sobre sua função. 6 - Fiscalização e suporte da CIPA. 7 - Oferecer programa de treinamento e mentoria para os colaboradores com maior dificuldade de compreensão da função. 8 - Elaborar descrições de cargos claras e precisas. 9 - Comunicar as responsabilidades de cada um de forma eficaz. 10 - Revisar e atualizar as descrições de cargos periodicamente.', '1 - Revisão e atualização das descrições de cargos. 2 - Comunicação clara das responsabilidades de cada função. 3 - Treinamento sobre as funções e responsabilidades.'),
  ('c1000000-0000-0000-0000-000000000018', 'a1100000-0000-0000-0000-000000000003', 'Falta de feedback construtivo', 'likert_1_5', 'negative', 2.0, true, true, 5, 18, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de treinamento dos gestores em habilidades de comunicação. 2 - Falta de tempo para realizar o feedback. 3 - Cultura organizacional que não valoriza o feedback. 4 - Medo de gerar conflitos ou desmotivar os trabalhadores.', 'Episódios depressivos Redução da autoestima, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Estabelecer um processo estruturado e regular para avaliar o desempenho dos funcionários. 2 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 3 - Definir, comunicar e acompanhar metas específicas para cada função. 4 - Capacitar a liderança para entregar feedbacks individuais e coletivos. 5 - Criar um espaço para que os líderes forneçam feedback construtivo aos colaboradores. 6 - Incentivar a cultura de segurança psicológica. 7 - Oferecer acomanhamento individual aos líderes com dificudade de entregar feedback construtivo. 8 - Criar programa de mentoria para aproximar líderes mais experientes de líderes menos experientes. 9 - Encorajar os trabalhadores a pedir feedback de seus líderes. 10 - Capacitar os gestores em habilidades de comunicação e feedback. 12 - Estabelecer rotinas de feedback regular. 13 - Criar uma cultura que valorize o feedback.', '1 - Implementação de um sistema de avaliação de desempenho. 2 - Treinamento em feedback para líderes. 3 - Incentivo à cultura de feedback.'),
  ('c1000000-0000-0000-0000-000000000019', 'a1100000-0000-0000-0000-000000000006', 'Falta de ferramentas e equipamentos adequados', 'likert_1_5', 'negative', 2.0, true, true, 0, 19, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de investimento em recursos. 2 - Falta de planejamento. 3 - Falta de comunicação entre gestão e equipe. 4 - Desconhecimento das necessidades dos trabalhadores.', 'Ansiedade, desmotivação, distúrbios do sono e conflitos interpessoais', '1 - Destinar recursos para a compra de ferramentas e equipamentos adequados, conforme NR- 17. 2 - Garantir que as ferramentas e equipamentos sejam armazenados, utilizados e mantidos de forma adequada. 3 - Fiscalização e suporte da CIPA. 4 - Garantir que todos os trabalhadores reportem as más condições ou a falta de equipamento adequado ao trabalho. 5 - Destinar recursos para a compra de ferramentas e equipamentos adequados, conforme NR- 17. 6 - Garantir a manutenção regular dos equipamentos. 7 - Ouvir as necessidades dos trabalhadores e atender às suas demandas.', '1 - Pesquisa com trabalhadores sobre as necessidades de ferramentas e equipamentos. 2 - Análise ergonômica do trabalho (AET). 3 - Manutenção preventiva dos equipamentos.'),
  ('c1000000-0000-0000-0000-000000000020', 'a1100000-0000-0000-0000-000000000003', 'Falta de justiça e práticas inconsistentes', 'likert_1_5', 'negative', 2.0, true, true, 6, 20, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de políticas claras e bem definidas. 2 - Falta de treinamento dos gestores sobre as políticas da empresa. 3 - Falta de critérios objetivos para a tomada de decisões. 4 - Favoritismo ou discriminação. 5 - Comunicação ineficaz sobre as regras e procedimentos.', 'Estresse, ansiedade, depressão, insegurança, tensão emocional, conflitos, fadiga mental', '1 - Divulgação clara das práticas e regimento interno. 2 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 3 - Fiscalização e suporte da CIPA. 4 - Oferecer EPI''s que diminuem a fadiga e o estresse, quando aplicável. 5 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 6 - Definir políticas e normas claras e transparentes. 7 - Capacitar os gestores para aplicar as políticas de forma justa. 8 - Utilizar critérios objetivos para a tomada de decisões.', '1 - Revisão e padronização das políticas e procedimentos da empresa. 2 - Treinamento dos gestores sobre a aplicação justa e consistente das regras. 3 - Canais de denúncia para relatar casos de injustiça ou inconsistência.'),
  ('c1000000-0000-0000-0000-000000000021', 'a1100000-0000-0000-0000-000000000005', 'Falta de oportunidades de desenvolvimento', 'likert_1_5', 'negative', 2.0, true, true, 0, 21, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de investimento em treinamento e desenvolvimento. 2 - Falta de programas de desenvolvimento de carreira. 3 - Cultura organizacional que não valoriza o aprendizado. 4 - Falta de clareza sobre as oportunidades de crescimento na empresa.', 'Episódios depressivos Redução da autoestima, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Elabora um Plano de Cargos, Carreiras e Salários (PCCS). 2 - Implementar programa de valorização e reconhecimento. 3 - Implementar o setor de Treinamento e Desenvolvimento. 4 - Elaborar Programa de Desenvolvimento Individual (PDI) e permitir o acesso a todos os colaboradores. 5 - Implementar programa de educação corporativa. 6 - Oferecer programa de Coaching & Mentoring. 7 - Oferecer orientação individual de carreira. 8 - Oferecer bolsas de estudo e incentivo à capacitação. 9 - Criar programas de desenvolvimento de carreira. 10 - Oferecer treinamento e capacitação para os trabalhadores. 11 - Valorizar e recompensar o aprendizado e o desenvolvimento.', '1 - Levantamento das necessidades de treinamento. 2 - Implementação de programas de desenvolvimento individual. 3 - Divulgação das oportunidades de desenvolvimento disponíveis.'),
  ('c1000000-0000-0000-0000-000000000022', 'a1100000-0000-0000-0000-000000000002', 'Horários inflexíveis', 'likert_1_5', 'negative', 2.0, true, true, 2, 22, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Natureza do trabalho (ex: produção contínua). 2 - Falta de políticas de flexibilização do trabalho. 3 - Cultura organizacional que não valoriza o equilíbrio entre vida pessoal e profissional.', 'Estresse, ansiedade, depressão, dificuldade de concentração, irritabilidade, isolamento social', '1 - Elaborar escalas de trabalho que minimizem o impacto na saúde e no sono, conforme NR- 17. 2 - Implementar um sistema de agendamento de folgas e férias flexível. 3 - Oferecer flexibilidade de horário, sempre que possível. 4 - Criar espaços de trabalho que permitam a adaptação às diferentes necessidades de horários. 5 - Oferecer espaços de descompressão mental e emocional. 6 - Criar escala que considerem as necessidades de flexibilidade de cada funcionário. 7 - Oferecer apoio para os funcionários que precisam conciliar o trabalho com outras responsabilidades (ex: filhos, estudos, etc.). 8 - Implementar políticas de flexibilização do trabalho (ex: horários flexíveis, trabalho remoto). 9 - Adotar sistemas de banco de horas para compensar horas extras, conforme Art. 59 da CLT.', '1 - Análise das necessidades de flexibilidade dos trabalhadores. 2 - Implementação de políticas de horários flexíveis. 3 - Pesquisas com trabalhadores sobre a satisfação com os horários de trabalho.'),
  ('c1000000-0000-0000-0000-000000000023', 'a1100000-0000-0000-0000-000000000002', 'Horas extras excessivas/ jornada de trabalho excessiva', 'likert_1_5', 'negative', 3.0, true, true, 3, 23, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Falta de planejamento. 2 - Falta de pessoal. 3 - Metas irrealistas. 4 - Cultura organizacional que valoriza o excesso de trabalho.', 'Síndrome de Burnout Estresse, ansiedade, depressão, dificuldade de concentração, distúrbios da memória, irritabilidade, isolamento social', '1 - Realizar monitoramento e controle rigoroso das horas extras, conforme CLT. 2 - Reavaliar e adequar o dimensiosamento de equipes. 3 - Oferecer flexibilidade de horário, sempre que possível. 4 - Adotar sistemas de banco de horas para compensar horas extras, conforme Art. 58 e 59 da CLT. 5 - Otimizar os processos de trabalho para reduzir a necessidade de horas extras. 6 - Fiscalização e suporte da CIPA. 7 - Oferecer apoio para os funcionários que precisam conciliar o trabalho com outras responsabilidades (ex: filhos, estudos, etc.). 8 - Oferecer espaços de descompressão mental e emocional. 9 - Melhorar o planejamento e a organização do trabalho, conforme NR-17. 10 - Implementar políticas de limitação das horas extras. 11 - Analisar dimensionamento de colaboradores.', '1 - Monitoramento rigoroso das horas extras. 2 - Análise das causas das horas extras excessivas. 3 - Implementação de medidas para reduzir a necessidade de horas extras.'),
  ('c1000000-0000-0000-0000-000000000024', 'a1100000-0000-0000-0000-000000000005', 'Insatisfação com a remuneração', 'likert_1_5', 'negative', 2.0, true, true, 1, 24, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Salário abaixo do mercado. 2 - Aumento do custo de vida. 3 - Falta de reconhecimento e recompensa. 4 - Trabalho de pouco valor ou propósito. 5 - Salário incompatível com as responsabilidades. 6 - Falta de clareza na política salarial.', 'Episódios depressivos Redução da autoestima, estresse, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Realizar uma pesquisa salarial para comparar a remuneração da empresa com o mercado. 2 - Revisar e comunicar a política de remuneração da empresa. 3 - Garantir uma remuneração justa e estável, conforme Art. 7º da CF. 4 - Implementar o Plano de Cargos, Carreiras e Salários (PCCS). 5 - Implementar um programa de reconhecimento para funcionários que se destacam. 6 - Oferecer capacitação em gestão financeira doméstica. 7 - Oferecer aconselhamento financeiro individualizado. 8 - Realizar pesquisas salariais regulares para garantir que a remuneração oferecida pela empresa esteja em linha com o mercado. 9 - Divulgar a política salarial da empresa para todos os trabalhadores. 10 - Oferecer um pacote de benefícios viável.', '1 - Pesquisa salarial para comparar a remuneração da empresa com o mercado. 2 - Revisão e comunicação da política de remuneração da empresa. 3 - Pesquisas com trabalhadores sobre a satisfação com a remuneração.'),
  ('c1000000-0000-0000-0000-000000000025', 'a1100000-0000-0000-0000-000000000007', 'Insatisfação com o trabalho', 'likert_1_5', 'negative', 2.0, true, true, 1, 25, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de reconhecimento e recompensa. 2 - Falta de oportunidades de desenvolvimento profissional. 3 - Trabalho de pouco valor ou propósito. 4 - Clima organizacional negativo. 5 - Desequilíbrio entre trabalho e vida pessoal.', 'Episódios depressivos Redução da autoestima, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Realizar pesquisas de clima organizacional para identificar as causas da insatisfação. 2 - Implementar um programa de reconhecimento e recompensa para valorizar o trabalho dos funcionários. 3 - Estimular a cultura organizacional de bem-estar. 4 - Criar espaços de trabalho mais agradáveis e confortáveis. 5 - Promover atividades de integração e lazer para os funcionários. 6 - Criar Programa de Desenvolvimento Individual (PDI) para trabalhador alcançar novos objetivos na carreira. 7 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 8 - Implementar programas de reconhecimento e recompensa. 9 - Oferecer oportunidades de desenvolvimento profissional. 10 - Melhorar o clima organizacional e a comunicação.', '1 - Pesquisas de clima organizacional para identificar as causas da insatisfação. 2 - Entrevistas com trabalhadores para entender suas necessidades e expectativas. 3 - Análise das taxas de rotatividade e absenteísmo.'),
  ('c1000000-0000-0000-0000-000000000026', 'a1100000-0000-0000-0000-000000000005', 'Insuficiência de capacitação para execução da tarefas', 'likert_1_5', 'negative', 3.0, true, true, 2, 26, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Falta de investimento em treinamento. 2 - Treinamento inadequado ou desatualizado. 3 - Falta de acompanhamento e feedback. 4 - Mudanças frequentes nos processos de trabalho sem treinamento adequado.', 'Transtorno de ansiedade generalizada Ansiedade, desmotivação, distúrbios do sono e conflitos interpessoais', '1 - Realizar um levantamento das necessidades de treinamento (LNT). 2 - Elaborar cronograma anual de treinamento. 3 - Disponibilizar material de apoio à capacitação (vídeos, livros, manuais etc) 4 - Implementar um programa de integração e capacitação para novos funcionários. 5 - Incentivar a participação nas capacitações oferecidas. 6 - Fiscalização e suporte da CIPA. 7 - Realizar avaliações de desempenho para identificar lacunas de competências. 8 - Criar Programa de Desenvolvimento Individual (PDI) para acelerar evolução do trabalhador com dificuldade. 9 - Identificar as necessidades de treinamento dos trabalhadores. 10 - Oferecer treinamento adequado e atualizado, conforme NR-1. 11 - Realizar acompanhamento e fornecer feedback.', '1 - Levantamento das necessidades de treinamento (LNT). 2 - Implementação de programas de treinamento e desenvolvimento. 3 - Avaliação da eficácia dos treinamentos.'),
  ('c1000000-0000-0000-0000-000000000027', 'a1100000-0000-0000-0000-000000000001', 'Metas elevadas, sem possibilidade de alcance', 'likert_1_5', 'negative', 3.0, true, true, 6, 27, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Falta de planejamento. 2 - Desconhecimento das condições reais de trabalho. 3 - Pressão excessiva por resultados. 4 - Falta de recursos.', 'Transtorno de Ansiedade Generalizada Estresse, ansiedade, depressão, dificuldade de concentração, distúrbios da memória, irritabilidade, isolamento social', '1 - Definição de prioridades e de metas realistas. 2 - Oferecer acompanhamento regular sobre o progresso das metas. 3 - Disponibilizar recursos para que os funcionários possam alcançar as metas. 4 - Promover uma cultura de trabalho em equipe. 5 - Fiscalização e suporte da CIPA. 6 - Realizar sessões de coaching e mentoring para os colaboradores com maior dificuldade de alcanças as metas. 7 - Oferecer espaços de descompressão mental e emocional. 8 - Definir metas realistas e alcançáveis, conforme NR-17. 9 - Envolver os trabalhadores na definição das metas. 10 - Fornecer os recursos necessários para atingir as meta.', '1 - Análise das metas e dos recursos disponíveis para alcançá-las. 2 - Pesquisas com trabalhadores sobre a percepção da viabilidade das metas. 3 - Acompanhamento do progresso em direção às metas.'),
  ('c1000000-0000-0000-0000-000000000028', 'a1100000-0000-0000-0000-000000000007', 'Monotonia', 'likert_1_5', 'negative', 2.0, true, true, 2, 28, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Tarefas repetitivas e sem desafios. 2 - Falta de variedade no trabalho. 3 - Falta de oportunidades de desenvolvimento profissional.', 'Episódios depressivos Redução da autoestima, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Implementar um programa de inovação e criatividade para estimular novas soluções para as atividades. 2 - Divulgar as oportunidades de desenvolvimento disponíveis. 3 - Implementar a rotação de tarefas e de funções, quando posível (Job Rotation). 4 - Criar espaços de trabalho mais estimulante, que favoreça a troca de experiências entre os trabalhadores. 5 - Ampliar as responsabilidades dos funcionários (job enrichment). 6 - Oferecer espaços de descompressão mental e emocional. 7 - Implementar a rotação de tarefas para aumentar a variedade no trabalho. 8 - Adicionar novas responsabilidades e desafios aos cargos. 9 - Oferecer treinamento para desenvolver novas habilidades.', '1 - Análise das tarefas para identificar oportunidades de aumentar a variedade. 2 - Implementação de programas de rotação de tarefas. 3 - Pesquisas com trabalhadores sobre a percepção da monotonia.'),
  ('c1000000-0000-0000-0000-000000000029', 'a1100000-0000-0000-0000-000000000005', 'Possibilidade de perda de emprego ou redução de salário', 'likert_1_5', 'negative', 3.0, true, true, 3, 29, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Instabilidade econômica global ou setorial. 2 - Reestruturações e fusões da empresa. 3 - Automação e novas tecnologias que substituem funções. 4 - Desempenho financeiro insatisfatório da empresa. 5 - Cortes de custos e políticas de austeridade. 6 - Contratos de trabalho temporários ou sem garantias. 7 - Terceirização de atividades para reduzir custos. 8 - Falta de transparência sobre a situação da empresa.', 'Transtorno de Ansiedade Generalizada Episódios depressivos Estresse, ansiedade, conflitos, irritabilidade, isolamento social', '1 - Comunicar de forma transparente a situação da empresa. 2 - Desenvolver e comunicar um plano de contingência para evitar demissões e reduções salariais. 3 - Disponibilizar informações sobre o mercado de trabalho e as oportunidades de emprego. 4 - Implementar programas de qualificação profissional para aumentar a empregabilidade dos funcionários. 5 - Fiscalização e suporte da CIPA. 6 - Oferecer JobHunter para os funcionários que estão em risco de perder o emprego. 7 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 8 - Comunicar claramente a situação da empresa e as perspectivas futuras. 9 - Desenvolver planos de contingência para evitar demissões. 10 - Oferecer apoio financeiro e psicológico aos trabalhadores afetados.', '1 - Comunicação transparente sobre a situação da empresa. 2 - Desenvolvimento e comunicação de um plano de contingência para evitar demissões e reduções salariais. 3 - Disponibilização de informações sobre o mercado de trabalho e as oportunidades de emprego.'),
  ('c1000000-0000-0000-0000-000000000030', 'a1100000-0000-0000-0000-000000000001', 'Sobrecarga de trabalho (muitas tarefas, prazos apertados)', 'likert_1_5', 'negative', 3.0, true, true, 7, 30, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Metas irrealistas e pouco claras. 2 - Número insuficiente de funcionários para a demanda. 3 - Prazos de entrega excessivamente curtos. 4 - Falta de organização e planejamento das tarefas. 5 - Priorização inadequada das atividades. 6 - Cultura organizacional que valoriza o excesso de trabalho. 7 - Falta de automatização de processos.', 'Síndrome de Burnout Estresse, ansiedade, irritabilidade, tensão e isolamento', '1 - Analisar a carga de trabalho para identificar as áreas com maior sobrecarga. 2 - Garantir pausas adequadas durante o expediente, conforme NR-17.5.5 e Art. 71 da CLT. 3 - Avaliar a distribuição de tarefas e redistribuir a carga de trabalho de forma mais equitativa, conforme NR-17. 4 - Investir em equipamentos e tecnologias para aumentar a eficiência do trabalho. 5 - Garantir pausas adequadas durante a jornada de trabalho. 6 - Fiscalização e suporte da CIPA. 7 - Oferecer suporte aos funcionários que estão sob pressão para lidar com a sobrecarga de trabalho. 8 - Oferecer espaços de descompressão mental e emocional. 9 - Avaliar a distribuição de tarefas e redistribuir a carga de trabalho de forma mais equitativa. 10 - Negociar prazos mais realistas com os clientes ou superiores. 11 - Implementar tecnologias e sistemas que automatizem tarefas repetitivas e burocráticas.', '1 - Análise da carga de trabalho. 2 - Implementação de técnicas de gestão do tempo. 3 - Redistribuição de tarefas. 4 - Monitoramento do estresse e da exaustão.'),
  ('c1000000-0000-0000-0000-000000000031', 'a1100000-0000-0000-0000-000000000001', 'Subcarga de trabalho (poucas tarefas, falta de desafios)', 'likert_1_5', 'negative', 2.0, true, true, 8, 31, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Automação de tarefas sem novas atribuições. 2 - Alocação inadequada de funções, abaixo da capacidade do trabalhador. 3 - Falta de oportunidades de desenvolvimento profissional. 4 - Tarefas repetitivas e sem complexidade. 5 - Falta de reconhecimento e valorização do trabalho. 6 - Processos de trabalho mal definidos.', 'Episódios depressivos Redução da autoestima, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Analisar a carga de trabalho para identificar as áreas com maior sobrecarga. 2 - Redistribuir as tarefas de forma mais equilibrada entre os funcionários. 3 - Implementar a rotação de tarefas e de funções, quando posível (Job Rotation). 4 - Criar espaços de trabalho mais estimulante, que favoreça a troca de experiências entre os trabalhadores. 5 - Incentivar a participação dos funcionários em treinamentos. 6 - Ampliar as responsabilidades dos funcionários (job enrichment). 7 - Aumentar os desafios técnicos dos trabalhadores subutilizados. 8 - Oferecer espaços de descompressão mental e emocional. 9 - Adicionar novas responsabilidades e desafios aos cargos existentes. 10 - Designar os trabalhadores para projetos especiais que exijam novas habilidades e conhecimentos. 11 - Oferecer oportunidades para os trabalhadores atuarem como mentores ou instrutores de outros colegas.', '1 - Análise das tarefas e das habilidades dos trabalhadores. 2 - Implementação de programas de enriquecimento de tarefas. 3 - Oferta de novos desafios e oportunidades de desenvolvimento.'),
  ('c1000000-0000-0000-0000-000000000032', 'a1100000-0000-0000-0000-000000000002', 'Trabalho com necessidade de variação de turnos', 'likert_1_5', 'negative', 2.0, true, true, 4, 32, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Instabilidade econômica. 2 - Falta de planejamento estratégico. 3 - Cultura organizacional que não valoriza a segurança no emprego. 4 - Reestruturações e fusões.', 'Estresse, ansiedade, depressão, dificuldade de concentração, irritabilidade, distúrbios do sono, isolamento social', '1 - Implementar escalas previsíveis e regulares, para minimizar a frequência das mudanças de turno. 2 - Comunicar os funcionários sobre as escalas de turnos com antecedência de 30 dias. 3 - Oferecer flexibilidade de turnos, sempre que possível. 4 - Disponibilizar espaços de descanso adequados para os funcionários que trabalham em turnos. 5 - Oferecer apoio para os funcionários que precisam conciliar o trabalho em turnos com responsabilidades pessoais. 6 - Monitorar a saúde dos funcionários que trabalham em turnos (sono, pressão arterial, alimentação). 7 - Elaborar escalas de trabalho que minimizem o impacto na saúde e no sono, conforme NR- 17. 8 - Oferecer adicional noturno e outros benefícios, conforme Art. 73 da CLT. 9 - Disponibilizar programas de apoio à saúde e bem-estar.', '1 - Análise das escalas de trabalho. 2 - Implementação de escalas previsíveis e regulares. 3 - Oferecimento de flexibilidade de turnos, sempre que possível. 4 - Monitoramento da saúde dos trabalhadores (sono, pressão arterial, alimentação).'),
  ('c1000000-0000-0000-0000-000000000033', 'a1100000-0000-0000-0000-000000000004', 'Trabalho em condições de difícil comunicação', 'likert_1_5', 'negative', 2.0, true, true, 3, 33, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Ruído excessivo no ambiente de trabalho. 2 - Isolamento físico dos trabalhadores. 3 - Barreiras linguísticas ou culturais entre colegas. 4 - Falta de equipamentos de comunicação adequados (ex: rádios, telefones). 5 - Cultura organizacional que não incentiva a comunicação aberta. 6 - Hierarquias rígidas que dificultam o fluxo de informações. 7 - Sobrecarga de informações, dificultando a identificação do que é relevante.', 'Episódios depressivos Redução da autoestima, estresse, irritabilidade, tensão emocional, diminuição do engajamento', '1 - Implementar canais de comunicação adequados para cada tipo de informação (ex: e-mail, intranet, murais, reuniões). 2 - Reduzir o ruído e outras distrações no ambiente de trabalho, conforme NR-15. 3 - Reduzir o ruído excessivo no ambiente de trabalho (ex: isolamento acústico, protetores auriculares). 4 - Disponibilizar equipamentos de comunicação adequados (ex: rádios, telefones, softwares de comunicação). 5 - Promover treinamentos em comunicação para os funcionários. 6 - Fiscalização e suporte da CIPA. 7 - Fornecer aos trabalhadores ferramentas de comunicação adequadas. 8 - Fornecer equipamento de proteção individual adequado. 9 - Adaptar a comunicação às necessidades individuais dos trabalhadores. 10 - Fornecer rádios, telefones ou outros dispositivos de comunicação. 11 - Oferecer treinamento em idiomas e comunicação intercultural. 12 - Incentivar a comunicação aberta e transparente.', '1 - Análise dos canais de comunicação. 2 - Implementação de ferramentas de comunicação adequadas. 3 - Treinamento em comunicação. 4 - Redução do ruído e de outras distrações no ambiente de trabalho.'),
  ('c1000000-0000-0000-0000-000000000034', 'a1100000-0000-0000-0000-000000000006', 'Trabalho em condições precárias', 'likert_1_5', 'negative', 2.0, true, true, 1, 34, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de investimento em infraestrutura. 2 - Falta de manutenção. 3 - Falta de atenção às necessidades dos trabalhadores.', 'Episódios depressivos, estresse, ansiedade, irritabilidade, desmotivação, distúrbios do sono e conflitos interpessoais', '1 - Garantir o cumprimento das Normas Regulamentadoras e outras legislações aplicáveis. 2 - Destinar recursos para a manutenção e melhoria das instalações, conforme Art. 70 da CF. 3 - Aplicar medidas disciplinares para os funcionários que não cumprem as normas de segurança e saúde. 4 - Garantir a conservação dos equipamentos e instalações. 5 - Estimular a cultura de saúde mental e segurança do trabalho. 6 - Divulgar informações sobre segurança e saúde de forma regular e acessível. 7 - Criar grupos de trabalho com representantes dos trabalhadores para desenvolver e implementar soluções para problemas específicos de segurança e saúde. 8 - Realizar simulados de emergência para preparar os funcionários para agir em situações de risco. 9 - Fiscalização e suporte da CIPA. 10 - Fornecer EPIs adequados para os riscos existentes. 11 - Oferecer espaços de descompressão mental e emocional. 12 - Oferecer treinamento específico para cada função e atividade, abordando os riscos e as medidas de controle. 13 - Destinar recursos para a manutenção e melhoria das instalações, conforme Art. 70 da CF. 14 - Priorizar a segurança e o bem-estar dos trabalhadores, conforme Art. 5º, inciso VI da Lei nº 6.514/77. 15 - Ouvir as necessidades dos trabalhadores e atender às suas demandas.', '1 - Inspeções regulares das instalações e equipamentos. 2 - Manutenção preventiva dos equipamentos. 3 - Atendimento às reclamações dos trabalhadores sobre as condições de trabalho.'),
  ('c1000000-0000-0000-0000-000000000035', 'a1100000-0000-0000-0000-000000000002', 'Trabalho noturno', 'likert_1_5', 'negative', 2.0, true, true, 5, 35, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Natureza do trabalho (ex: profissionais de saúde, segurança). 2 - Falta de políticas de compensação e suporte para os trabalhadores. 3 - Impacto na saúde e no sono. 4 - Dificuldade em conciliar trabalho e vida pessoal.', 'Estresse, ansiedade, depressão, dificuldade de concentração, irritabilidade, distúrbios do sono, isolamento social', '1 - Evitar escalas de trabalho noturno rotativos, priorizando turnos fixos. 2 - Garantir o adicional noturno e outros benefícios, conforme Art. 73 da CLT. 3 - Elaborar escalas de trabalho que minimizem o impacto na saúde e no sono, conforme NR- 17. 4 - Oferecer flexibilidade de turnos, sempre que possível. 5 - Criar espaços de descanso adequados para os funcionários que trabalham à noite. 6 - Manter o ambiente e as condições sanitárias adequados ao uso. 7 - Oferecersuporte psicológico individual para funcionários com dificuldades no trabalho noturno. 8 - Oferecer apoio para os funcionários que precisam conciliar o trabalho com outras responsabilidades pessoais. 9 - Oferecer adicional noturno e outros benefícios, conforme Art. 73 da CLT. 10 - Disponibilizar programas de apoio à saúde e bem-estar. 11 - Elaborar escalas de trabalho que minimizem o impacto na saúde e no sono.', '1 - Análise das escalas de trabalho noturno. 2 - Implementação de medidas para minimizar o impacto na saúde e no sono. 3 - Monitoramento da saúde dos trabalhadores (sono, pressão arterial, alimentação). 4 - Disponibilização de espaços de descanso adequados.'),
  ('c1000000-0000-0000-0000-000000000036', 'a1100000-0000-0000-0000-000000000002', 'Trabalho remunerado por produção', 'likert_1_5', 'negative', 3.0, true, true, 6, 36, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Pressão por produtividade. 2 - Incerteza sobre a renda. 3 - Falta de controle sobre o ritmo de trabalho.', 'Transtorno de ansiedade generalizada Ansiedade, desmotivação, distúrbios do sono e conflitos interpessoais', '1 - Definir metas de produção realistas e alcançáveis, considerando as condições de trabalho e as capacidades dos trabalhadores. 2 - Oferecer recursos e apoio para que os funcionários possam alcançar as metas de produção dentro de condições seguras e saudáveis. 3 - Promover uma cultura de valorização da qualidade do trabalho, em vez de apenas da quantidade. 4 - Investir em equipamentos e tecnologias que aumentem a eficiência do trabalho e reduzam o esforço físico e mental. 5 - Oferecer treinamento em gestão de tempo e organização do trabalho aos trabalhadores com dificuldades. 6 - Oferecer suporte psicológico aos funcionários que estão sob pressão para cumprir metas de produção. 7 - Garantir uma remuneração justa e estável, conforme Art. 7º da CF. 8 - Dar aos trabalhadores mais controle sobre o ritmo de trabalho. 9 - Priorizar a segurança em detrimento da produtividade.', '1 - Análise das metas de produção. 2 - Monitoramento do ritmo de trabalho. 3 - Pesquisas com trabalhadores sobre a percepção da pressão por produção.'),
  ('c1000000-0000-0000-0000-000000000037', 'a1100000-0000-0000-0000-000000000006', 'Trabalho sob condições insalubres', 'likert_1_5', 'negative', 2.0, true, true, 2, 37, 'Safe2Mind', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Natureza do trabalho. 2 - Presença de agentes físicos (ruído, umidade, radiação, temperaturas extremas, pressão, vibração). 3 - Presença de agentes químicos (poeiras, gases, vapores, substâncias químicas perigosas). 4 - Presença de agentes biológicos (vírus, bactérias, fungos, parasitas, protozoários)', 'Estresse, ansiedade, episódios depressivos, tensão e transtorno de humor', '1 - Reduzir ao máximo a exposição dos trabalhadores aos agentes insalubres. 2 - Informar os trabalhadores sobre os riscos presentes no ambiente de trabalho e as medidas de controle adotadas. 3 - Oferecer treinamento sobre os riscos presentes no ambiente de trabalho e as medidas de controle. 4 - Criar áreas de descanso adequadas para que os trabalhadores possam se recuperar durante as pausas. 5 - Fiscalização e suporte da CIPA. 6 - Fornecer EPIs adequados para os riscos. 7 - Treinar os trabalhadores sobre o uso correto, a conservação e a higienização dos EPIs. 8 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 9 - Identificar os limites de tolerância, através de análise técnica especializada. 10 - Implementar as medidas de controle e prevenção, conforme preconizam as NR''s. 11 - Garantir o uso eficiente do equipamento de proteção individual - EPI. 12 - Capacitar, adequadamente, os colaboradores da função. 13 - Oferecer suporte psicológico em casos de manifestação de estresse, ansiedade ou medo.', '1 - Avaliação dos riscos ambientais. 2 - Implementação de medidas de controle (EPCs e EPIs). 3 - Monitoramento da exposição dos trabalhadores aos agentes insalubres. 4 - Realização de exames médicos periódicos.'),
  ('c1000000-0000-0000-0000-000000000038', 'a1100000-0000-0000-0000-000000000006', 'Trabalho sob condições perigosas', 'likert_1_5', 'negative', 3.0, true, true, 3, 38, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Natureza do trabalho. 2 - Manuseio de produto explosivo ou inflamável. 3 - Trabalho com eletricidade (instalações, equipamentos, redes etc) 4 - Trabalho em altura. 5 - Trabalho em espaço confinado. 6 - Atividades com motocicleta. 7 - Operações com máquinas e equipamentos perigosos (prensas, guilhotinas, serras, injetoras etc). 8 - Atividade de segurança patrimonial. 9 - Atividade submersa. 10 - Atividades com animais perigosos.', 'Estresse, ansiedade, episódios depressivos, tensão e transtorno de humor', '1 - Reduzir ao máximo a exposição dos trabalhadores aos agentes perigosas. 2 - Elaborar e comunicar os procedimentos de segurança para cada atividade perigosa. 3 - Oferecer treinamento sobre os riscos presentes no ambiente de trabalho e as medidas de controle. 4 - Treinar planos de emergência para cada situação de risco. 5 - Promover a cultura de segurança do trabalho. 6 - Fiscalização e suporte da CIPA. 7 - Fornecer EPIs adequados para os riscos. 8 - Treinar os trabalhadores sobre o uso correto, a conservação e a higienização dos EPIs. 9 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 10 - Remover completamente a fonte de perigo, quando possível, substituindo por alternativas mais seguras ou menos perigosas. 11 - Isolar as pessoas do perigo, quando possível, através de controle de engenharia. 12 - Aperfeiçoar a forma de trabalho, através de controle de procedimento padrão. 13 - Proteger o trabalhador com EPI correto.', '1 - Análise de riscos. 2 - Implementação de medidas de controle (procedimentos de segurança, equipamentos de proteção). 3 - Treinamento dos trabalhadores sobre os riscos e as medidas de controle. 4 - Realização de simulados de emergência.'),
  ('c1000000-0000-0000-0000-000000000039', 'a1100000-0000-0000-0000-000000000001', 'Trabalho sob forte pressão', 'likert_1_5', 'negative', 3.0, true, true, 9, 39, 'Safe2Mind', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Metas irrealistas. 2 - Falta de pessoal. 3 - Falta de planejamento e organização do trabalho. 4 - Pressão por produtividade. 5 - Falta de automatização de tarefas. 6 - Cultura organizacional que valoriza o excesso de trabalho.', 'Síndrome de Burnout Estresse, ansiedade, irritabilidade, tensão e isolamento', '1 - Organizar o trabalho para permitir aos trabalhadores gerenciar suas tarefas e prazos de forma eficiente. 2 - Alinhar, claramente, as expectativas, as prioridades e os prazos. 3 - Estabelecer canais de comunicação e denúncia, confidenciais e eficientes. 4 - Fornecer feedback regular sobre o desempenho dos trabalhadores. 5 - Oferecer, aos trabalhadores, autonomia e controle sobre suas tarefas e horários, sempre que possível. 6 - Capacitar os líderes para oferecer apoio e orientação aos trabalhadores que se sentem sob forte pressão. 7 - Incentivar a realização de pausas regulares durante a jornada. 8 - Implementar programas de bem-estar e qualidade de vida no trabalho. 9 - Oferecer treinamento em gestão de tempo e organização do trabalho. 10 - Oferecer espaços de descompressão mental e emocional. 11 - Disponibilizar apoio psicológico e emocional seguindo o Art. 6º da Lei nº 8.080/90 (Lei Orgânica da Saúde). 12 - Otimizar processos e distribuir tarefas de forma equitativa, conforme NR-17. 13 - Reavaliar e aumentar o número de funcionários para atender à demanda. 14 - Definir prioridades claras e realistas.', '1 - Análise da carga de trabalho. 2 - Implementação de técnicas de gestão do tempo. 3 - Oferta de apoio psicológico. 4 - Monitoramento do estresse e da exaustão.'),
  ('c1000000-0000-0000-0000-000000000040', 'a1100000-0000-0000-0000-000000000001', 'Altas exigências cognitivas', 'likert_1_5', 'negative', 2.0, true, true, 10, 40, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Tarefas complexas sem tempo adequado. 2 - Multitarefa excessiva. 3 - Sobrecarga de informações. 4 - Falta de pausas mentais. 5 - Decisões sob pressão.', 'Fadiga crônica relacionada ao trabalho; transtornos do sono e da atenção.', '1 - Redesenho de tarefas cognitivas e rotação de funções. 2 - Rodízio de funções cognitivamente exigentes entre equipes. 3 - Treinamento em gestão de tempo e mindfulness. 4 - Pausas cognitivas programadas. 5 - Redução da multitarefa por redistribuição. 6 - Treinamentos para gestão do tempo e prioridades.', '1 - Avaliações periódicas de carga mental (Entrevista e observação).'),
  ('c1000000-0000-0000-0000-000000000041', 'a1100000-0000-0000-0000-000000000007', 'Altas exigências emocionais', 'likert_1_5', 'negative', 3.0, true, true, 3, 41, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Contato frequente com sofrimento alheio (ex: saúde, educação). 2 - Necessidade de esconder emoções. 3 - Conflitos interpessoais frequentes. 4 - Atendimento ao público.', 'Transtornos de adaptação, transtornos ansiosos relacionados ao trabalho.', '1 - Treinamento de inteligência emocional e acolhimento. 2 - Grupos de apoio e supervisão terapêutica para funções emocionais. 3 - Programa de assistência Psicológica. 4 - Suporte psicoterapêutico. 5 - Rodízio de funções emocionais intensas. 6 - Espaços de descompressão.', '1 - Relatórios de incidentes emocionais e absenteísmo.'),
  ('c1000000-0000-0000-0000-000000000042', 'a1100000-0000-0000-0000-000000000003', 'Baixa autoeficácia', 'likert_1_5', 'negative', 3.0, true, true, 7, 42, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Falta de feedback positivo. 2 - Ausência de capacitação. 3 - Supervisão punitiva. 4 - Metas inalcançáveis. 5 - Tarefas sem clareza.', 'Transtornos depressivos e ansiosos leves; desmotivação ocupacional.', '1 - Programa de mentoria interna e feedback estruturado. 2 - Oficinas de formação e desenvolvimento de competências técnicas e comportamentais. 3 - Coaching profissional. 4 - Capacitações contínuas. 5 - Programas de mentoria. 6 - Feedbacks regulares e construtivos.', '1 - Avaliações de desempenho e PDI.'),
  ('c1000000-0000-0000-0000-000000000043', 'a1100000-0000-0000-0000-000000000004', 'Baixa confiança entre pares', 'likert_1_5', 'negative', 2.0, true, true, 4, 43, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Cultura organizacional competitiva. 2 - Ausência de cooperação. 3 - Falhas de comunicação. 4 - Histórico de traições ou disputas não resolvidas.', 'Transtornos de estresse ocupacional; retraimento e isolamento social.', '1 - Regras claras de conduta e cultura organizacional. 2 - Atividades de integração e dinâmicas de equipe para aumento da confiança. 3 - Mediação de conflitos. 4 - Oficinas de cooperação e comunicação. 5 - Mediação de conflitos estruturada. 6 - Cultura de transparência e escuta ativa.', '1 - Avaliação de clima organizacional entre equipes.'),
  ('c1000000-0000-0000-0000-000000000044', 'a1100000-0000-0000-0000-000000000003', 'Baixa confiança na gerência', 'likert_1_5', 'negative', 3.0, true, true, 8, 44, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Decisões arbitrárias. 2 - Falta de transparência. 3 - Ausência de escuta ativa. 4 - Promessas não cumpridas. 5 - Estilo autoritário.', 'Transtornos de ajustamento; transtornos depressivos reativos.', '1 - Treinamento de liderança transparente e participativa. 2 - Reuniões abertas com escuta ativa (gestão participativa). 3 - Canal de comunicação direta e segura. 4 - Comunicação transparente e frequente. 5 - Participação dos trabalhadores em decisões. 6 - Liderança com escuta ativa e empática.', '1 - Pesquisas de clima e satisfação com gestão (NPS).'),
  ('c1000000-0000-0000-0000-000000000045', 'a1100000-0000-0000-0000-000000000005', 'Baixa possibilidades de desenvolvimento', 'likert_1_5', 'negative', 2.0, true, true, 4, 45, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de planos de carreira. 2 - Estagnação funcional. 3 - Ausência de treinamentos. 4 - Desprezo por talentos internos. 5 - Tarefas repetitivas.', 'Desmotivação ocupacional; transtornos do humor relacionados ao bloqueio de carreira.', '1 - Plano de carreira e promoções (PCCS - Plano de Cargos, Carreiras e Salários). 2 - Trilhas de aprendizagem por área. 3 - Participação em cursos e seminários. 4 - Plano de carreira estruturado. 5 - Acesso igualitário a cursos e formações. 6 - Avaliações de desempenho com metas claras.', '1 - Registro de participação e progressão de carreira.'),
  ('c1000000-0000-0000-0000-000000000046', 'a1100000-0000-0000-0000-000000000007', 'Burnout', 'likert_1_5', 'negative', 4.0, true, true, 4, 46, 'COPSOQ - II', 4, 'Alta Incapacidade de realizar as tarefas do trabalho', '1 - Sobrecarga crônica de trabalho. 2 - Falta de reconhecimento. 3 - Pressão constante por resultados. 4 - Falta de apoio. 5 - Gestão desumana.', 'Síndrome de burnout (exaustão ocupacional); transtornos de estresse crônico.', '1 - Redução de carga horária crítica. 2 - Semana da saúde mental e campanhas educativas. 3 - Suporte Psicológico e acompanhamento médico. 4 - Redução de sobrecarga com revisão de demandas. 5 - Apoio psicológico institucional. 6 - Políticas de equilíbrio trabalho/vida.', '1 - Monitoramento de afastamentos por estresse, ansiedade e esgotamento.'),
  ('c1000000-0000-0000-0000-000000000047', 'a1100000-0000-0000-0000-000000000004', 'Comportamentos ofensivos', 'likert_1_5', 'negative', 4.0, true, true, 5, 47, 'COPSOQ - II', 4, 'Alta Incapacidade de realizar as tarefas do trabalho', '1 - Ambientes permissivos ao assédio. 2 - Lideranças omissas ou coniventes. 3 - Políticas disciplinares frágeis. 4 - Ausência de canais de denúncia.', 'Transtorno de estresse pós-traumático; ansiedade crônica; assédio moral como fator contribuinte.', '1 - Política de tolerância zero e canal de denúncia. 2 - Treinamentos antiassédio e respeito no trabalho. 3 - Apoio emocional e orientação jurídica. 4 - Política de tolerância zero ao assédio. 5 - Canais seguros de denúncia. 6 - Treinamento sobre respeito e diversidade.', '1 - Indicadores de ocorrências e resolutividade.'),
  ('c1000000-0000-0000-0000-000000000048', 'a1100000-0000-0000-0000-000000000002', 'Conflito trabalho/ família', 'likert_1_5', 'negative', 3.0, true, true, 7, 48, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Jornada excessiva. 2 - Exigência de disponibilidade fora do horário. 3 - Imprevisibilidade de turnos. 4 - Cultura de produtividade tóxica.', 'Transtornos de adaptação; insônia; ansiedade situacional.', '1 - Flexibilização de jornada e banco de horas. 2 - Políticas de teletrabalho e escalas alternadas. 3 - Suporte com planejamento e orientação familiar. 4 - Jornada flexível e banco de horas. 5 - Regimes híbridos ou home office (quando possível). 6 - Ações de apoio à parentalidade.', '1 - Questionários sobre conciliação trabalho-vida.'),
  ('c1000000-0000-0000-0000-000000000049', 'a1100000-0000-0000-0000-000000000004', 'Conflitos laborais', 'likert_1_5', 'negative', 4.0, true, true, 6, 49, 'COPSOQ - II', 4, 'Alta Incapacidade de realizar as tarefas do trabalho', '1 - Competição entre equipes. 2 - Liderança parcial ou ausente. 3 - Objetivos mal definidos. 4 - Carga mal distribuída. 5 - Comunicação deficiente.', 'Transtornos comportamentais no trabalho; ansiedade e depressão relacionadas a ambiente hostil.', '1 - Protocolos de mediação formal de conflitos. 2 - Criação do Comitê interno de mediação de relações interpessoais. 3 - Sessões de escuta ativa, suporte Psicológico e orientação. 4 - Círculos de diálogo e escuta. 5 - Mediação profissional de conflitos. 6 - Acordos de convivência.', '1 - Frequência de relatos e resolubilidade.'),
  ('c1000000-0000-0000-0000-000000000050', 'a1100000-0000-0000-0000-000000000005', 'Déficit nas recompensas', 'likert_1_5', 'negative', 3.0, true, true, 5, 50, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Remuneração abaixo do esperado. 2 - Promoções injustas. 3 - Reconhecimento apenas negativo. 4 - Falta de feedback positivo.', 'Depressão relacionada à desvalorização no trabalho; transtornos mo vacionais.', '1 - Reestruturação de planos de cargos e salários (PCCS). 2 - Programa de reconhecimento por resultados (PPR - Programa de Participação nos Resultados). 3 - Treinamentos e feedback formal sobre desempenho. 4 - Reconhecimento institucional público. 5 - Reestruturação de políticas de mérito. 6 - Inclusão de incentivos não monetários.', '1 - Revisões salariais, taxa de atratividade e pesquisas de engajamento.'),
  ('c1000000-0000-0000-0000-000000000051', 'a1100000-0000-0000-0000-000000000007', 'Estresse', 'likert_1_5', 'negative', 3.0, true, true, 5, 51, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Sobrecarga emocional e mental. 2 - Demandas incompatíveis com os recursos. 3 - Clima de insegurança. 4 - Prazos curtos. 5 - Metas inalcançáveis.', 'Transtorno de estresse ocupacional; agravamento de doenças cardiovasculares e digestivas.', '1 - Monitoramento de carga de trabalho e pausas obrigatórias. 2 - Práticas de ergonomia organizacional e melhoria de fluxos de trabalho. 3 - Suporte Psicológico preventivos e emergencial. 4 - Programa de gestão do estresse (ex.: mindfulness, relaxamento, ginástica laboral). 5 - Avaliação da carga de trabalho. 6 - Suporte psicoterapêutico.', '1 - Avaliações periódicas de estresse, engajamento, absenteísmo, rotatividade.'),
  ('c1000000-0000-0000-0000-000000000052', 'a1100000-0000-0000-0000-000000000001', 'Exigências quantitativas', 'likert_1_5', 'negative', 3.0, true, true, 11, 52, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Grande volume de trabalho. 2 - Prazos rígidos e curtos. 3 - Déficit de pessoal. 4 - Ausência de tecnologias de apoio.', 'Fadiga ocupacional; transtornos de sono e humor; risco aumentado de burnout.', '1 - Redimensionamento das metas e revisão de processos. 2 - Redefinição de equipes conforme volume de trabalho. 3 - Treinamento em gestão de tempo e produtividade. 4 - Redimensionamento de equipes. 5 - Automação de tarefas repetitivas. 6 - Monitoramento de horas extras.', '1 - Avaliações de carga por setor.'),
  ('c1000000-0000-0000-0000-000000000053', 'a1100000-0000-0000-0000-000000000007', 'Falta de saúde geral', 'likert_1_5', 'negative', 2.0, true, true, 6, 53, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Exposição contínua ao estresse. 2 - Alimentação inadequada no trabalho. 3 - Ergonomia precária. 4 - Ausência de pausas ou atividade física.', 'Doenças psicossomáticas inespecíficas; síndrome da fadiga persistente.', '1 - Programa de vigilância à saúde ocupacional. 2 - Campanhas de prevenção e exames periódicos coletivos. 3 - Encaminhamento a especialistas via PCMSO. 4 - Programas de promoção da saúde (atividade física, alimentação, avaliação médica). 5 - Pausas obrigatórias. 6 - Programa de saúde mental corporativa.', '1 - Fichas clínicas e atestados médicos.'),
  ('c1000000-0000-0000-0000-000000000054', 'a1100000-0000-0000-0000-000000000003', 'Injustiça e desrespeito', 'likert_1_5', 'negative', 3.0, true, true, 9, 54, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Favorecimento pessoal. 2 - Decisões arbitrárias. 3 - Punições desproporcionais. 4 - Exclusão de grupos minoritários.', 'Transtornos de ajustamento com humor misto; risco de quadros paranoides situacionais.', '1 - Código de ética e conduta e canal de ouvidoria ativo. 2 - Sensibilização sobre diversidade, equidade, inclusão e respeito. 3 - Acolhimento, suporte Psicológico e orientação jurídica. 4 - Código de conduta com aplicação efetiva. 5 - Treinamentos sobre justiça organizacional. 6 - Acesso democrático a processos decisórios.', '1 - Denúncias registradas e resolução formal.'),
  ('c1000000-0000-0000-0000-000000000055', 'a1100000-0000-0000-0000-000000000007', 'Insatisfação no trabalho', 'likert_1_5', 'negative', 2.0, true, true, 7, 55, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de propósito. 2 - Tarefas monótonas. 3 - Clima organizacional ruim. 4 - Sensação de inutilidade. 5 - Frustração com a organização.', 'Transtornos depressivos leves; distúrbios emocionais de origem ocupacional.', '1 - Plano com cronograma de melhorias, conforme resultados confirmados na pesquisas de satisfação. 2 - Reuniões de gestão participativas para escuta. 3 - Planos de desenvolvimento individual (PDI). 4 - Rodízio de tarefas e enriquecimento de função. 5 - Avaliações periódicas de clima organizacional. 6 - Processos participativos de gestão.', '1 - Avaliações do clima organizacional e taxa de colaboradores em desenvolvimento.'),
  ('c1000000-0000-0000-0000-000000000056', 'a1100000-0000-0000-0000-000000000005', 'Insegurança laboral', 'likert_1_5', 'negative', 3.0, true, true, 6, 56, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Contratos temporários ou instáveis. 2 - Reestruturações frequentes. 3 - Ameaças de demissão. 4 - Rumores não esclarecidos.', 'Transtornos de ansiedade generalizada; distúrbios do sono e estresse contínuo.', '1 - Criação e comunicação de contratos estáveis e comunicação clara e objetiva de mudanças (quando houver). 2 - Garantias coletivas em acordos e convenções. 3 - Apoio na compreensão de direitos e garantias. 4 - Comunicação clara sobre reestruturações. 5 - Garantia de estabilidade mínima. 6 - Programas de transição e recolocação.', '1 - Absenteísmo e rotatividade.'),
  ('c1000000-0000-0000-0000-000000000057', 'a1100000-0000-0000-0000-000000000003', 'Má qualidade da liderança', 'likert_1_5', 'negative', 4.0, true, true, 10, 57, 'COPSOQ - II', 4, 'Alta Incapacidade de realizar as tarefas do trabalho', '1 - Chefias desorganizadas, autoritárias ou ausentes. 2 - Falta de escuta. 3 - Ausência de exemplo ético. 4 - Despreparo para gerir pessoas.', 'Estresse crônico, burnout, hostilidade organizacional; transtornos de humor reativos.', '1 - Avaliação 360º nos líderes e treinamento em liderança humanizada. 2 - Workshops de comunicação e alinhamento de gestão. 3 - Coaching individual para gestores com baixo desempenho. 4 - Capacitação contínua em liderança empática. 5 - Avaliação 360º de líderes. 6 - Códigos de conduta para gestores.', '1 - Avaliação de liderança por equipe e conflitos resolvidos.'),
  ('c1000000-0000-0000-0000-000000000058', 'a1100000-0000-0000-0000-000000000004', 'Pouca cooperação no trabalho', 'likert_1_5', 'negative', 2.0, true, true, 7, 58, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Incentivo à competição entre colegas. 2 - Metas individuais em detrimento das coletivas. 3 - Falta de integração entre setores.', 'Isolamento social, fadiga emocional, estresse interpessoal.', '1 - Estímulo formal à metas compartilhadas e gestão colaborativa. 2 - Dinâmicas de grupo e projetos intersetoriais. 3 - PDI com foco em trabalho em equipe. 4 - Atividades de integração. 5 - Metas de equipe com reconhecimento coletivo. 6 - Programas de fortalecimento de redes de apoio.', '1 - Tempo de produtividade em atividades de cooperação.'),
  ('c1000000-0000-0000-0000-000000000059', 'a1100000-0000-0000-0000-000000000003', 'Pouca influência no trabalho', 'likert_1_5', 'negative', 3.0, true, true, 11, 59, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Ausência de autonomia para decidir. 2 - Processos centralizados. 3 - Decisões impostas sem consulta. 4 - Microgestão.', 'Depressão situacional, perda de autonomia, risco de burnout.', '1 - Implementação de comitê de gestão participativa. 2 - Criação de espaços de escuta e decisão compartilhada. 3 - Inclusão do trabalhador em propostas de melhoria. 4 - Delegação de responsabilidades. 5 - Comitês de decisão com participação dos trabalhadores. 6 - Avaliações com sugestões para melhoria.', '1 - Reuniões e pautas com participação ativa.'),
  ('c1000000-0000-0000-0000-000000000060', 'a1100000-0000-0000-0000-000000000002', 'Pouca previsibilidade de rotina', 'likert_1_5', 'negative', 2.0, true, true, 8, 60, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Alterações constantes nos turnos ou tarefas. 2 - Falta de planejamento. 3 - Comunicação tardia de mudanças. 4 - Ambiente caótico.', 'Estresse reativo; transtornos por incerteza organizacional.', '1 - Publicação de planejamento semanal/mensal transparente. 2 - Alinhamento mensal entre setores e turnos. 3 - Garantir acesso aos cronogramas e atividades pré-definidas do setor. 4 - Planejamento semanal claro. 5 - Agendas fixas de reuniões e entregas. 6 - Comunicação antecipada de mudanças.', '1 - Atrasos na entrega e conflitos de agenda entre setores.'),
  ('c1000000-0000-0000-0000-000000000061', 'a1100000-0000-0000-0000-000000000003', 'Pouca transparência do papel laboral desempenhado', 'likert_1_5', 'negative', 2.0, true, true, 12, 61, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Falta de clareza nas atribuições. 2 - Superposição de tarefas entre cargos. 3 - Comunicação ambígua de responsabilidades.', 'Transtornos de identidade ocupacional; ansiedade organizacional crônica.', '1 - Revisão e publicação das Descrições de Cargos e Salários. 2 - Apresentação de funções e responsabilidades das equipes. 3 - Feedback individual sobre desempenho e expectativas. 4 - Descrições de cargo atualizadas. 5 - Reuniões de alinhamento funcional. 6 - Planos de integração para novos membros.', '1 - Erros e retrabalhos por ambiguidade.'),
  ('c1000000-0000-0000-0000-000000000062', 'a1100000-0000-0000-0000-000000000004', 'Pouco apoio social de colegas', 'likert_1_5', 'negative', 3.0, true, true, 8, 62, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Ambiente competitivo. 2 - Isolamento intencional de colegas. 3 - Cultura de individualismo. 4 - Falta de integração entre novatos e veteranos.', 'Depressão leve a moderada; isolamento; dificuldades relacionais.', '1 - Políticas de integração de novos colaboradores. 2 - Eventos internos e dinâmicas coletivas de relacionamento interpessoal. 3 - Estímulo a padrinhos e redes de apoio informal (Mentores de novos colaboradores). 4 - Grupos de apoio por afinidade. 5 - Projetos colaborativos. 6 - Mentoria entre pares.', '1 - Relatos e observação de isolamento ou exclusão.'),
  ('c1000000-0000-0000-0000-000000000063', 'a1100000-0000-0000-0000-000000000003', 'Pouco apoio social dos superiores', 'likert_1_5', 'negative', 4.0, true, true, 13, 63, 'COPSOQ - II', 4, 'Alta Incapacidade de realizar as tarefas do trabalho', '1 - Chefia distante ou sobrecarregada. 2 - Foco exclusivo em resultados. 3 - Ausência de escuta ou orientação. 4 - Clima hierárquico rígido.', 'Transtornos de adaptação; estresse contínuo; burnout.', '1 - Treinamentos dos líderes em comunicação, empatia, feedback, escuta ativa e desenvolvimento de equipes. 2 - Acompanhamento mensal do desenvolvimento das liderança. 3 - Criação de espaços de conversa com superiores (líderes e colaboradores). 4 - Supervisão mais próxima e efetiva. 5 - Reuniões periódicas de acompanhamento. 6 - Formação em escuta ativa para chefias.', '1 - Feedbacks negativos e conflitos hierárquicos.'),
  ('c1000000-0000-0000-0000-000000000064', 'a1100000-0000-0000-0000-000000000005', 'Pouco compromisso face ao local de trabalho', 'likert_1_5', 'negative', 2.0, true, true, 7, 64, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Cultura organizacional desmotivadora. 2 - Falta de alinhamento com valores da empresa. 3 - Baixa identificação com a missão da instituição.', 'Desengajamento; apatia profissional; transtornos motivacionais.', '1 - Implementação de projetos de identidade e cultura organizacional. 2 - Campanhas de identidade e pertencimento. 3 - Estimular engajamento em projetos transversais. 4 - Reforço de missão e propósito organizacional. 5 - Programas de reconhecimento e valorização. 6 - Espaço para iniciativas voluntárias.', '1 - Indicadores de turnover e absenteísmo.'),
  ('c1000000-0000-0000-0000-000000000065', 'a1100000-0000-0000-0000-000000000002', 'Problemas em dormir', 'likert_1_5', 'negative', 2.0, true, true, 9, 65, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Ruminância mental por demandas excessivas. 2 - Turnos irregulares. 3 - Conflitos emocionais no trabalho. 4 - Estresse constante.', 'Insônia; distúrbios relacionados ao sono por estresse ocupacional.', '1 - Revisão dos turnos adequados à legislação e ritmo biológico. 2 - Projeto de redução de horas extras e sobrejornada. 3 - Avaliação de autorelato da qualidade de sono. 4 - Programa de higiene do sono. 5 - Flexibilidade de jornada para casos de insônia crônica. 6 - Redução de exposição a telas e e-mails fora do expediente.', '1 - Relatos de insônia e cansaço.'),
  ('c1000000-0000-0000-0000-000000000066', 'a1100000-0000-0000-0000-000000000001', 'Ritmo de trabalho acelerado', 'likert_1_5', 'negative', 2.0, true, true, 12, 66, 'COPSOQ - II', 2, 'Baixa Leve redução temporária no desempenho ou na qualidade de vida', '1 - Demandas urgentes contínuas. 2 - Processos engessados. 3 - Falta de pausas. 4 - Cultura de produtividade imediata. 5 - Excesso de tarefas simultâneas.', 'Fadiga ocupacional persistente; ansiedade e sintomas físicos por sobrecarga.', '1 - Reorganização de processos e fluxos produtivos. 2 - Revisão e adequação de metas e prazos realistas. 3 - Treinamento em planejamento, gestão de prioridades e pausas programadas. 4 - Revisão de metas e cronogramas. 5 - Pausas obrigatórias e estruturadas. 6 - Avaliação ergonômica da organização das tarefas.', '1 - Registros de horas e erros por pressa.'),
  ('c1000000-0000-0000-0000-000000000067', 'a1100000-0000-0000-0000-000000000007', 'Sintomas depressivos', 'likert_1_5', 'negative', 3.0, true, true, 8, 67, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Clima tóxico. 2 - Falta de sentido nas tarefas. 3 - Isolamento social. 4 - Sobrecarga e sensação de impotência crônica.', 'Transtornos depressivos recorrentes ou únicos; transtorno distímico.', '1 - Encaminhamento ao Programa de Saúde Mental. 2 - Roda de conversa em grupo e apoio emocional coletivo. 3 - Atendimento individual com Psicólogo. 4 - Encaminhamento para apoio psicológico. 5 - Ações de engajamento e sentido do trabalho. 6 - Monitoramento contínuo de sinais de adoecimento.', '1 - CID em atestados e acompanhamento psicossocial.'),
  ('c1000000-0000-0000-0000-000000000068', 'a1100000-0000-0000-0000-000000000005', 'Trabalho sem significado', 'likert_1_5', 'negative', 3.0, true, true, 8, 68, 'COPSOQ - II', 3, 'Moderada Redução significativa no desempenho ou na qualidade de vida', '1 - Tarefas burocráticas sem impacto percebido. 2 - Falta de alinhamento com valores pessoais. 3 - Pouca liberdade para inovar ou contribuir.', 'Transtorno existencial; perda de sentido da atividade laboral; risco elevado de depressão.', '1 - Implementação de Programas de reconhecimento e impacto social do trabalho. 2 - Compartilhamento de resultados e conquistas da equipe. 3 - Planejamento individual de carreira e reavaliação de função. 4 - Reconexão entre atividades e missão institucional. 5 - Escuta dos colaboradores sobre o propósito do trabalho. 6 - Oportunidades para inovação e protagonismo.', '1 - Relatos de desmotivação e falta de sentido.');
insert into public.campaigns (id, questionnaire_id, name, sector, unit, status, start_date, end_date, language, created_at)
